// Code should be written in Go/Golang
// Write a function to find the minimum cost path to reach (m, n) from (0, 0) for the given cost matrix cost[][] and a position (m, n) in cost[][].
// Examples:
// >>> min_cost([[1, 2, 3], [4, 8, 2], [1, 5, 3]], 2, 2)
// >>> 8
// >>> min_cost([[2, 3, 4], [5, 9, 3], [2, 6, 4]], 2, 2)
// >>> 12
// >>> min_cost([[3, 4, 5], [6, 10, 4], [3, 7, 5]], 2, 2)
// >>> 16
func min_cost (cost [][]int, m int, n int) int {
    if m == 0 || n == 0 {
        return 0
    }
    if cost[m][n] == 0 {
        return Infinity
    }
    return min(min_cost(cost, m - 1, n) + cost[m][n], min_cost(cost, m, n - 1) + cost[m][n])
}

