package main

import (
    "encoding/json"
    "reflect"
)
// Code should be written in Go/Golang
// Write a function to convert snake case string to camel case string.
// Examples:
// >>> snake_to_camel('python_program')
// >>> 'PythonProgram'
// >>> snake_to_camel('python_language')
// >>> ('PythonLanguage')
// >>> snake_to_camel('programming_language')
// >>> ('ProgrammingLanguage')
func snake_to_camel (word string) string {
    var words []string{
        word.Split("_")
    }
    var result []string{
        words.ForEach(s => result.Add(s[0].ToUpper() + s.Substring(1)))
    }
    result.Remove(result.Index(result.Last()))
    return result.Join("")
}

