    * {{string("gold"), string("zilver")}, {string("aluminium"), string("magnesium")}, {string("bronze"), string("steel")}}
    */
vector<vector<string>> sortSublists(vector<vector<string>> inputList) {
        // For each element in the input list, sort its constituent elements.
        for (size_t i = 0; i < inputList.size(); i++) {
            std::sort(inputList[i].begin(), inputList[i].end());
        }

        // Return the list of sorted strings.
        return inputList;
}

