// >>> extract_missing([(7, 2), (15, 19), (38, 50)], 1, 52)
// >>> [(1, 7), (2, 52), (2, 15), (19, 52), (19, 38), (50, 52)]
func extract_missing (test_list [][]int, strt_val int, stop_val int) [][]int {
    res := make([][]int, 0)
    for i := 0; i < len(test_list); i++ {
        if test_list[i][0] > strt_val {
            res = append(res, []int{strt_val, test_list[i][0]})
            strt_val = test_list[i][1]
        }
        if strt_val < stop_val {
            res = append(res, []int{strt_val, stop_val})
        }
    }
    return res
}

