                temp = nestedlist[i][j];
                k = 1;
                while (k < m) {
                    if (nestedlist[i][k] != temp) {
                        break;
                    }
                    k++;
                }
                if (k == m) {
                    result = temp;
                    break;
                }
            }
        }
        return result;
}

