    */
string assignFreq(vector<vector<int>> testList) {
        string result = "[";
        for (auto v : testList) {
            result += "(";
            for (auto i : v) {
                result += i + ", ";
            }
            result = result.slice(0, -2);
            result += "), ";
        }
        result = result.slice(0, -2);
        result += "]";
        return result;
}

