// Write a function to assign frequency to each tuple in the given tuple list.
// Examples:
// >>> assign_freq([(6, 5, 8), (2, 7), (6, 5, 8), (6, 5, 8), (9, ), (2, 7)] )
// >>> '[(6, 5, 8, 3), (2, 7, 2), (9, 1)]'
// >>> assign_freq([(4, 2, 4), (7, 1), (4, 8), (4, 2, 4), (9, 2), (7, 1)] )
// >>> '[(4, 2, 4, 2), (7, 1, 2), (4, 8, 1), (9, 2, 1)]'
// >>> assign_freq([(11, 13, 10), (17, 21), (4, 2, 3), (17, 21), (9, 2), (4, 2, 3)] )
// >>> '[(11, 13, 10, 1), (17, 21, 2), (4, 2, 3, 2), (9, 2, 1)]'
func assign_freq (test_list [][]int) string {
    // 1. Initialize a hash table to store the frequency of each tuple.
    // 2. Traverse the given list and assign frequency to each tuple.
    // 3. Return the resultant hash table.
    map := make(map map[string]int)
    for _, _, freq := range test_list {
        map[string(freq)] += 1
    }
    return map
}

