import java.io.*;
import java.lang.*;
import java.util.*;
import java.math.*;


class AssignFreq {
    /**
        * * Write a function to assign frequency to each tuple in the given tuple list.
        *
        * > assignFreq([[6, 5, 8], [2, 7], [6, 5, 8], [6, 5, 8], [9], [2, 7]])
        * "[(6, 5, 8, 3), (2, 7, 2), (9, 1)]"
        * > assignFreq([[4, 2, 4], [7, 1], [4, 8], [4, 2, 4], [9, 2], [7, 1]])
        * "[(4, 2, 4, 2), (7, 1, 2), (4, 8, 1), (9, 2, 1)]"
        * > assignFreq([[11, 13, 10], [17, 21], [4, 2, 3], [17, 21], [9, 2], [4, 2, 3]])
        * "[(11, 13, 10, 1), (17, 21, 2), (4, 2, 3, 2), (9, 2, 1)]"
        */
    public static String assignFreq(List<List<Integer>> testList) {
            // Write your code here
            Map<Integer, Integer> map = new HashMap<>();
            for (List<Integer> list : testList) {
                for (int i = 0; i < list.size(); i++) {
                    if (map.containsKey(list.get(i))) {
                        map.put(list.get(i), map.get(list.get(i)) + 1);
                    } else {
                        map.put(list.get(i), 1);
                    }
                }
            }
            List<String> result = new ArrayList<>();
            for (Map.Entry<Integer, Integer> entry : map.entrySet()) {
                result.add(entry.getKey() + "," + entry.getValue());
            }
            return result.toString();
    }
}

