// Code should be written in Go/Golang
// Write a function to find the maximum product from the pairs of tuples within a given list.
// Examples:
// >>> max_product_tuple([(2, 7), (2, 6), (1, 8), (4, 9)] )
// >>> 36
// >>> max_product_tuple([(10,20), (15,2), (5,10)] )
// >>> 200
// >>> max_product_tuple([(11,44), (10,15), (20,5), (12, 9)] )
// >>> 484
func max_product_tuple (list1 [][]int) int {
    var max_product []int64
    var max_product_tuple []int64
    var i int
    var j int
    var product int64
    var tuple1 []int64
    var tuple2 []int64
    for i := 0; i < len(list1); i++ {
        for j := 0; j < len(list1[i]); j++ {
            tuple1 = list1[i][j]
            tuple2 = list1[i][j + 1]
            product = tuple1[0] * tuple2[0]
            if (product > max_product) {
                max_product = product
                max_product_tuple = []int64{tuple1, tuple2}
            }
        }
    }
    return max_product_tuple
}

