// >>> check_triplet([1, 4, 5, 6, 7, 8, 5, 9], 8, 6, 0)
// >>> False
// >>> check_triplet([10, 4, 2, 3, 5], 5, 15, 0)
// >>> True
func check_triplet (A []int, n int, sum int, count int) bool {
    for _, v := range A {
        for _, w := range A {
            for _, z := range A {
                if (v + w + z) == sum {
                    count += 1
                    if count == n {
                        return true
                    }
                }
            }
        }
    }
    return false
}

