    public static int findLength(String string, int n) {
            int max = 0;
            int count = 0;
            for (int i = 0; i < n; i++) {
                count += string.charAt(i) == '0' ? 1 : -1;
                max = Math.max(max, count);
                if (count < 0) {
                    count = 0;
                }
            }
            return max;
    }
}

