package main

import (
    "sort"
    "encoding/json"
    "reflect"
)
// Code should be written in Go/Golang
// Write a function to sort a list of elements using pancake sort.
// Examples:
// >>> pancake_sort([15, 79, 25, 38, 69])
// >>> [15, 25, 38, 69, 79]
// >>> pancake_sort([98, 12, 54, 36, 85])
// >>> [12, 36, 54, 85, 98]
// >>> pancake_sort([41, 42, 32, 12, 23])
// >>> [12, 23, 32, 41, 42]
func pancake_sort (nums []int) []int {
    for i, j in pairs(nums) {
        for k, l in pairs(nums) {
            if i < k && j > l {
                swap(nums, i, k)
            }
        }
    }
    return nums
}

