        int sum = 0;
        vector<int> path = vector<int>(m, n);
        for (int i = 0; i < m; i++) {
            for (int j = 0; j < n; j++) {
                if (i == 0 || j == 0) {
                    path[i][j] = tri[i][j];
                } else {
                    path[i][j] = Math.max(path[i - 1][j], path[i][j - 1]) + tri[i][j];
                }
                sum = Math.max(sum, path[i][j]);
            }
        }
        return sum;
}

