// Code should be written in Go/Golang
// Write a function to find the maximum total path sum in the given triangle.
// Examples:
// >>> max_path_sum([[1, 0, 0], [4, 8, 0], [1, 5, 3]], 2, 2)
// >>> 14
// >>> max_path_sum([[13, 0, 0], [7, 4, 0], [2, 4, 6]], 2, 2)
// >>> 24
// >>> max_path_sum([[2, 0, 0], [11, 18, 0], [21, 25, 33]], 2, 2)
// >>> 53
func max_path_sum (tri [][]int, m int, n int) int {
    for i := m-1; i >= 0; i-- {
        for j := i+1; j < n; j++ {
            if (tri[i+1][j] > tri[i+1][j+1]) {
                tri[i][j] += tri[i+1][j]
            } else {
                tri[i][j] += tri[i+1][j+1]
            }
        }
    }
    return tri[0][0]
}

