func merge_sort (x []int) []int {
    if len(x) == 1 {
        return x
    }
    else {
        var mid := len(x) / 2
        var left := merge_sort(x[0..mid])
        var right := merge_sort(x[mid..len(x)])
        return merge(left, right)
    }
}

