        * > mergeSort([3, 1, 4, 9, 8])
        * [1, 3, 4, 8, 9]
        */
    public static List<Integer> mergeSort(List<Integer> x) {
            if (x.size() == 1) {
                return x;
            }
            List<Integer> x2 = new ArrayList<>();
            int i = 0;
            while (i < x.size()) {
                x2.add(x.get(i));
                i++;
            }
            Collections.sort(x2);
            return x2;
    }
}

