import java.io.*;
import java.lang.*;
import java.util.*;
import java.math.*;


class ExtractUnique {
    /**
        * * Write a function to extract unique values from the given dictionary values.
        *
        * > extractUnique({"msm": [5, 6, 7, 8], "is": [10, 11, 7, 5], "best": [6, 12, 10, 8], "for": [1, 2, 5]})
        * [1, 2, 5, 6, 7, 8, 10, 11, 12]
        * > extractUnique({"Built": [7, 1, 9, 4], "for": [11, 21, 36, 14, 9], "ISP": [4, 1, 21, 39, 47], "TV": [1, 32, 38]})
        * [1, 4, 7, 9, 11, 14, 21, 32, 36, 38, 39, 47]
        * > extractUnique({"F": [11, 13, 14, 17], "A": [12, 11, 15, 18], "N": [19, 21, 15, 36], "G": [37, 36, 35]})
        * [11, 12, 13, 14, 15, 17, 18, 19, 21, 35, 36, 37]
        */
    public static List<Integer> extractUnique(HashMap<String, List<Integer>> testDict) {
            List<Integer> unique = new ArrayList<>();
            for (String key : testDict.keySet()) {
                List<Integer> list = testDict.get(key);
                for (int i = 0; i < list.size(); i++) {
                    if (!unique.contains(list.get(i))) {
                        unique.add(list.get(i));
                    }
                }
            }
            return unique;
    }
}

